import { z } from 'zod';

const objectIdRegex = /^[0-9a-fA-F]{24}$/;

// DAT schemas
export const createDatSessionSchema = z.object({
  body: z.object({
    course_student_id: z.string().regex(objectIdRegex, 'Mã enrollment phải là ObjectId hợp lệ'),
    session_type: z.enum(['dat', 'cabin']).default('dat'),
    date: z.string().min(1, 'Ngày bắt buộc'),
    timeStart: z.string().min(1, 'Giờ bắt đầu bắt buộc'),
    timeEnd: z.string().min(1, 'Giờ kết thúc bắt buộc'),
    distance_km: z.number().optional(),
    notes: z.string().optional(),
  }),
});

// Health check schema
export const updateHealthCheckSchema = z.object({
  body: z.object({
    course_student_id: z.string().regex(objectIdRegex, 'Mã enrollment phải là ObjectId hợp lệ'),
    status: z.enum(['Chờ khám', 'Đủ điều kiện', 'Không đủ điều kiện']),
    date: z.string().optional(),
    hospital: z.string().min(1, 'Phòng khám/bệnh viện bắt buộc'),
    note: z.string().optional(),
  }),
});

// Bulk update schema
export const bulkUpdateCourseStatusSchema = z.object({
  body: z.object({
    courseIds: z.array(z.string()).min(1, 'Phải chọn ít nhất 1 khóa'),
    newStatus: z.enum(['draft', 'ongoing', 'completed', 'canceled']),
  }),
});

// Payment schemas
export const createPaymentSchema = z.object({
  body: z.object({
    studentId: z.string().min(1, 'Mã học viên bắt buộc'),
    amount: z.number().positive('Số tiền phải > 0'),
    phase: z.string().optional(),
    method: z.enum(['cash', 'transfer', 'other']).optional(),
  }),
});

import type {} from '../types/express.d';
import { Request, Response } from 'express';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import { DatService } from '@/application/services/dat.service';

const datService = new DatService();

/**
 * Get DAT Analytics for the Progress Page
 */
export const getDatAnalytics = catchAsync(async (req: Request, res: Response) => {
  const analytics = await datService.getDatAnalytics((req as any).user);
  res.statusSuccess(analytics, 'DAT Analytics retrieved successfully');
});

/**
 * Add a new DAT Session
 */
export const addDatSession = catchAsync(async (req: Request, res: Response) => {
  const session = await datService.addDatSession(req.body);
  res.statusSuccess(session, 'DAT Session added successfully');
});

/**
 * Get DAT Sessions for a specific enrollment
 */
export const getStudentDatSessions = catchAsync(async (req: Request, res: Response) => {
  const { enrollmentId } = req.params;
  const sessions = await datService.getStudentDatSessions(enrollmentId as string);
  res.statusSuccess(sessions, 'Student DAT sessions retrieved successfully');
});

import { DatRepository } from '@/infrastructure/repositories/dat.repository';
import { IDatSession } from '@/infrastructure/database/models/dat_session.model';
import { StudentRepository } from '@/infrastructure/repositories/student.repository';
import { ExamRepository } from '@/infrastructure/repositories/exam.repository';
import { CourseStudentModel } from '@/infrastructure/database/models/course_student.model';
import { AppError } from '@/domain/exceptions/app-error';

export class DatService {
  private datRepository: DatRepository;
  private studentRepository: StudentRepository;
  private examRepository: ExamRepository;

  constructor() {
    this.datRepository = new DatRepository();
    this.studentRepository = new StudentRepository();
    this.examRepository = new ExamRepository();
  }

  async addDatSession(data: {
    course_student_id: string;
    session_type?: string;
    date: string;
    timeStart: string;
    timeEnd: string;
    distance_km?: number;
    notes?: string;
  }): Promise<IDatSession> {
    // Verify enrollment exists
    const enrollment = await CourseStudentModel.findById(data.course_student_id).exec();
    if (!enrollment) {
      throw new AppError('Enrollment not found', 404);
    }

    // Map date + time fields to start_time / end_time Date objects
    const startTime = new Date(`${data.date}T${data.timeStart}:00.000Z`);
    const endTime = new Date(`${data.date}T${data.timeEnd}:00.000Z`);

    return await this.datRepository.create({
      course_student_id: data.course_student_id as any,
      session_type: (data.session_type || 'dat') as any,
      start_time: startTime,
      end_time: endTime,
      distance_km: data.distance_km ?? 0,
      notes: data.notes,
    });
  }

  async getStudentDatSessions(courseStudentId: string): Promise<IDatSession[]> {
    return await this.datRepository.findByCourseStudent(courseStudentId);
  }

  async getStudentDatStats(courseStudentId: string) {
    return await this.datRepository.getStatsByStudent(courseStudentId);
  }

  async getDatAnalytics(currentUser?: any) {
    const [datStats, studentStats, examStats] = await Promise.all([
      this.datRepository.getDatStats(currentUser),
      this.studentRepository.getStats(currentUser),
      this.examRepository.getStats('graduation' as any, currentUser),
    ]);

    // Format chart data (Ensure all 6 months are present)
    const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const chartData = [];
    for (let i = 0; i < 6; i++) {
      const d = new Date();
      d.setMonth(d.getMonth() - (5 - i));
      const m = d.getMonth() + 1;
      const y = d.getFullYear();
      const monthlyData = datStats.monthlyKm || [];
      const found = monthlyData.find((item: any) => item._id.month === m && item._id.year === y);
      chartData.push({
        label: monthNames[m - 1],
        value: found ? Math.round(found.total_km) : 0,
      });
    }

    const passRate =
      examStats && examStats.total > 0 ? Math.round(((examStats.passed || 0) / examStats.total) * 100) : 0;

    return {
      monthly_growth: chartData,
      global_stats: {
        total_students: studentStats?.total || 0,
        active_students: studentStats?.active || 0,
        completed_km_count: datStats.completedKmCount || 0,
        pass_rate: passRate,
      },
    };
  }
}

import mongoose, { Schema, Document, Types } from 'mongoose';

export interface ICourseStudent extends Document {
  student_id: Types.ObjectId; // References Student(student_infos)
  course_id: Types.ObjectId; // References Course(course_infos)
  stadium_id?: Types.ObjectId | null;
  teacher_id?: Types.ObjectId | null;
  sale_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  status: 'unfinished' | 'finished' | 'canceled';
  km: number;
  hour: string;
  fee: number;
  paid_fee: number;
  balance?: any; // Treasury balance for this enrollment
  contract_date?: Date | null;
  status_detail?: string;
  progress_flags?: {
    theory_completed: boolean;
    sand_yard_completed: boolean;
    simulation_completed: boolean;
    dat_completed: boolean;
    cabin_completed: boolean;
    graduation_eligible: boolean;
  };
  health_check?: {
    status: string;
    date: Date | null;
    hospital: string | null;
    note: string | null;
  };
  created_at: Date;
  updated_at: Date;
}

const CourseStudentSchema = new Schema<ICourseStudent>(
  {
    student_id: { type: Schema.Types.ObjectId, ref: 'StudentInfos', required: true, index: true },
    course_id: { type: Schema.Types.ObjectId, ref: 'Courses', required: true, index: true },
    stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums', default: null },
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
    sale_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
    license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
    status: {
