// @ts-nocheck
import mongoose from 'mongoose';
import bcrypt from 'bcrypt';
import dotenv from 'dotenv';
import { fakerVI as faker } from '@faker-js/faker';
import logger from '../infrastructure/logging/logger';
import { UserModel as User, UserRole, UserGender, UserStatus } from '../infrastructure/database/models/user.model';
import { StudentModel as Student } from '../infrastructure/database/models/student.model';
import { CourseModel as Course } from '../infrastructure/database/models/course.model';
import { CourseStudentModel as CourseStudent } from '../infrastructure/database/models/course_student.model';
import { CityModel as City } from '../infrastructure/database/models/city.model';
import { StadiumModel as Stadium } from '../infrastructure/database/models/stadium.model';
import { LessonModel as Lesson, LessonCategory, LessonStatus } from '../infrastructure/database/models/lesson.model';
import { ExamModel as Exam } from '../infrastructure/database/models/exam.model';
import { DatSessionModel as DatSession, DatSessionType } from '../infrastructure/database/models/dat_session.model';
import { PaymentModel as Payment, PaymentType } from '../infrastructure/database/models/payment.model';
import { ExamScheduleModel as ExamSchedule } from '../infrastructure/database/models/exam_schedule.model';
import ExamBatch from '../infrastructure/database/models/exam_batch.model';
import { LicenseCategoryModel as LicenseCategory } from '../infrastructure/database/models/license_category.model';
import { NotificationModel as Notification } from '../infrastructure/database/models/notification.model';
import Announcement from '../infrastructure/database/models/announcement.model';
import VipQr from '../infrastructure/database/models/vip_qr.model';
import connectDB from '@/infrastructure/database/mongodb';

dotenv.config();

/**
 * THE ULTIMATE SEEDER v5.0 - Full Operational Fidelity
 * Fixes: Status distribution, Future data (Upcoming Lessons/Exams), Urgent Tasks
 */
const runUltimateSeed = async () => {
  try {
    const TODAY = new Date('2026-04-10T08:00:00Z');
    logger.info(`🧊 INITIALIZING ULTIMATE SEEDER V5.0 (Simulated Today: ${TODAY.toLocaleDateString()})...`);
    await connectDB();
    logger.info('✅ DATABASE CONNECTED');

    // --- PHASE 0: PURGE ---
    logger.info('🧹 PURGING ALL COLLECTIONS...');
    const collections = Object.values(mongoose.connection.models);
    for (const model of collections) {
      await model.deleteMany({});
    }

    // --- PHASE 1: FOUNDATION ---
    logger.info('🏗️ SEEDING FOUNDATION...');
    const licenseData = [
      { name: 'Hạng A1', code: 'A1', description: 'Xe máy dưới 175cm3' },
      { name: 'Hạng A2', code: 'A2', description: 'Xe máy từ 175cm3 trở lên' },
      { name: 'Hạng B1', code: 'B1', description: 'Ô tô số tự động (không kinh doanh)' },
      { name: 'Hạng B2', code: 'B2', description: 'Ô tô số sàn' },
      { name: 'Hạng C', code: 'C', description: 'Xe tải trên 3.5 tấn' },
      { name: 'Hạng D', code: 'D', description: 'Xe khách từ 10-30 chỗ' },
    ];
    const licenseCategories = await LicenseCategory.insertMany(licenseData);

    const cityData = [
      { name: 'Hà Nội', code: 'HN' },
      { name: 'Thành phố Hồ Chí Minh', code: 'HCM' },
      { name: 'Đà Nẵng', code: 'DN' },
      { name: 'Cần Thơ', code: 'CT' },
    ];
    const cities = await City.insertMany(cityData);

    const stadiums = await Stadium.insertMany(
      cityData.map((c, i) => ({
        name: `Sân sát hạch ${c.name} - Cơ sở ${i + 1}`,
        address: `${faker.location.streetAddress()}, ${c.name}`,
        city: c.name,
        isActive: true,
        phone: `091${i.toString().padStart(7, '8')}`,
      })),
    );

    // --- PHASE 2: PERSONNEL ---
    logger.info('👥 SEEDING PERSONNEL...');
    const adminPass = await bcrypt.hash('Admin@123456', 10);
    const teacherPass = await bcrypt.hash('Teacher@123456', 10);
    const studentPass = await bcrypt.hash('Student@123', 10);

    const admin = await User.create({
      first_name: 'Quản trị',
      last_name: 'Hệ thống',
      email: 'admin@qlhv.vn',
      username: 'admin@qlhv.vn',
      password: adminPass,
      role: UserRole.Admin,
      status: UserStatus.Active,
      phone: '0988776655',
      address: 'Hà Nội',
      identity_card: '001000000001',
    });

    const teachers = [];
    for (let i = 1; i <= 24; i++) {
      teachers.push(
        await User.create({
          first_name: faker.person.firstName(),
          last_name: faker.person.lastName(),
          email: `teacher${i}@qlhv.vn`,
          username: `teacher${i}@qlhv.vn`,
          password: teacherPass,
          role: UserRole.Teacher,
          status: UserStatus.Active,
          phone: faker.helpers.fromRegExp(/0[35789][0-9]{8}/),
          address: faker.location.streetAddress(),
          identity_card: faker.string.numeric(12),
        }),
      );
    }

    // --- PHASE 3: ACADEMIC FRAMEWORK ---
    const courses = [];
    for (const lc of licenseCategories) {
      courses.push(
        await Course.create({
          name: `Khóa ${lc.code} - K25`,
          code: `${lc.code}-K25`,
          course_fee: lc.code.startsWith('B') ? 18000000 : 22000000,
          status: 'completed',
          start_date: new Date('2025-10-01'),
          end_date: new Date('2026-01-30'),
          license_category_id: lc._id,
        }),
      );
      courses.push(
        await Course.create({
          name: `Khóa ${lc.code} - K26`,
          code: `${lc.code}-K26`,
          course_fee: lc.code.startsWith('B') ? 19000000 : 24000000,
          status: 'ongoing',
          start_date: new Date('2026-02-15'),
          end_date: new Date('2026-06-15'),
          license_category_id: lc._id,
        }),
      );
      courses.push(
        await Course.create({
          name: `Khóa ${lc.code} - K27`,
          code: `${lc.code}-K27`,
          course_fee: 20000000,
          status: 'draft',
          start_date: new Date('2026-05-10'),
          license_category_id: lc._id,
        }),
      );
    }

    // --- PHASE 4: BALANCED STUDENT GENERATION ---
    logger.info('🎓 GENERATING 1,100 STUDENTS (BALANCED DISTRIBUTION)...');
    const TOTAL_STUDENTS = 1100;
    const BATCH_SIZE = 100;

    for (let b = 0; b < TOTAL_STUDENTS; b += BATCH_SIZE) {
      const batchEnd = Math.min(b + BATCH_SIZE, TOTAL_STUDENTS);
      const studentPromises = [];

      for (let i = b; i < batchEnd; i++) {
        studentPromises.push(
          (async () => {
            const rand = i / TOTAL_STUDENTS;
            const license = faker.helpers.arrayElement(licenseCategories);
            const city = faker.helpers.arrayElement(cities);
            const email = `hv${i.toString().padStart(4, '0')}@edu.qlhv.vn`;

            const user = await User.create({
              first_name: faker.person.firstName(),
              last_name: faker.person.lastName(),
              email,
              username: email,
              password: studentPass,
              role: UserRole.Student,
              phone: faker.helpers.fromRegExp(/0[35789][0-9]{8}/),
              status: UserStatus.Active,
              address: faker.location.streetAddress(),
              identity_card: faker.string.numeric(12),
            });

            // Accurate Status Distribution (Matches Dashboard Boxes)
            let statusDetail = 'Chờ KSK';
            let state = 'lead';
            if (rand < 0.1) {
              statusDetail = 'Chờ KSK';
              state = 'lead';
            } else if (rand < 0.2) {
              statusDetail = 'Đã KSK';
              state = 'lead';
            } else if (rand < 0.3) {
              statusDetail = 'Đã nộp HS';
              state = 'lead';
            } else if (rand < 0.6) {
              statusDetail = 'Đang học';
              state = 'active';
            } else if (rand < 0.7) {
              statusDetail = 'Đang thi';
              state = 'active';
            } else if (rand < 0.75) {
              statusDetail = 'Thi lại';
              state = 'active';
            } else if (rand < 0.95) {
              statusDetail = 'Đã đậu';
              state = 'graduated';
            } else {
              statusDetail = 'Nghỉ học';
              state = 'dropped';
            }

            const student = await Student.create({
              user_id: user._id,
              region_id: city._id,
              status_detail: statusDetail,
              license_category_id: license._id,
              progress_flags: {
                theory_completed: state === 'graduated' || rand > 0.4,
                cabin_completed: state === 'graduated' || statusDetail === 'Đang thi',
                dat_completed: state === 'graduated',
              },
              tuition: { total: 0, paid: 0 },
            });

            // Course and Enrollment
            const targetCourseStatus = state === 'graduated' ? 'completed' : state === 'lead' ? 'draft' : 'ongoing';
            const course =
              courses.find(
                (c) => c.license_category_id.toString() === license._id.toString() && c.status === targetCourseStatus,
              ) || courses[0];

            const teacher = faker.helpers.arrayElement(teachers);
            // Debt diversity (30% of active students have debt)
            const isDebtor = state === 'active' && faker.number.float() < 0.3;
            const paid = isDebtor
              ? course.course_fee - faker.number.int({ min: 1000000, max: 8000000 })
              : state === 'lead'
                ? 500000
                : course.course_fee;

            // 70% of students enrolled in courses, 30% are "Chờ vào khóa"
            const shouldEnrol = i < 800;

            if (shouldEnrol) {
              const enrollment = await CourseStudent.create({
                student_id: student._id,
                course_id: course._id,
                teacher_id: teacher._id,
                sale_id: admin._id,
                stadium_id: faker.helpers.arrayElement(stadiums)._id,
                fee: course.course_fee,
                paid_fee: paid,
                status: state === 'graduated' ? 'finished' : 'unfinished',
                status_detail: statusDetail, // CRITICAL: Mirror status to enrollment
                contract_date: new Date('2026-02-01'),
              });

              await Student.updateOne(
                { _id: student._id },
                { 'tuition.total': course.course_fee, 'tuition.paid': paid, course_id: course._id },
              );

              // OPERATIONAL DATA (Lessons & Payments)
              if (state !== 'lead') {
                // Past Lessons (Completed)
                await Lesson.create({
                  course_student_id: enrollment._id,
                  student_id: user._id,
                  teacher_id: teacher._id,
                  name: 'Thực hành Sa hình',
                  category: LessonCategory.Practice,
                  status: LessonStatus.Completed,
                  start_time: new Date(TODAY.getTime() - 2 * 24 * 60 * 60 * 1000),
                  end_time: new Date(TODAY.getTime() - 2 * 24 * 60 * 60 * 1000 + 2 * 3600 * 1000),
                  confirmed: true,
                  km: 20,
                  stadium_id: stadiums[0]._id,
                });

                // Future Lessons (Upcoming) - Only for 'Đang học'
                if (statusDetail === 'Đang học') {
                  await Lesson.create({
                    course_student_id: enrollment._id,
                    student_id: user._id,
                    teacher_id: teacher._id,
                    name: 'Thực hành Đường trường - Ca sáng',
                    category: LessonCategory.Practice,
                    status: LessonStatus.Pending,
                    start_time: new Date(TODAY.getTime() + 2 * 24 * 60 * 60 * 1000), // Day after tomorrow
                    end_time: new Date(TODAY.getTime() + 2 * 24 * 60 * 60 * 1000 + 3 * 3600 * 1000),
                    confirmed: false,
                    stadium_id: stadiums[0]._id,
                  });
                }

                // DAT Logs
                if (['B1', 'B2', 'C'].includes(license.code)) {
                  const km = state === 'graduated' ? 810 : faker.number.int({ min: 100, max: 700 });
                  await DatSession.create({
                    course_student_id: enrollment._id,
                    session_type: DatSessionType.Dat,
                    distance_km: km,
                    start_time: new Date('2026-03-01'),
                    end_time: new Date('2026-03-15'),
                  });
                }

                // Payment record
                await Payment.create({
                  course_student_id: enrollment._id,
                  type: PaymentType.TuitionFee,
                  payment_date: new Date('2026-02-05'),
                  received_fee: paid,
                  is_received: true,
                });
              }
            } else {
              // Un-enrolled students should have a pending status
              await Student.updateOne({ _id: student._id }, { status: 'Chờ KSK', status_detail: 'Chờ KSK' });
            }
          })(),
        );
      }
      await Promise.all(studentPromises);
      logger.info(`   📦 Seeded ${batchEnd}/${TOTAL_STUDENTS} students...`);
    }

    // --- PHASE 5: FUTURE EXAMS ---
    logger.info('🏆 SEEDING UPCOMING EXAMS...');
    for (const lc of licenseCategories) {
      // Future Batch (Populates Dashboard Upcoming list)
      const batch = await ExamBatch.create({
        name: `Sát hạch ${lc.code} - Khóa K26`,
        vehicleType: lc.code.startsWith('A') ? 'Xe máy' : 'Ô tô',
        region: 'Hà Nội',
        venue: 'Sân PCCC',
        status: 'upcoming',
        examDate: new Date(TODAY.getTime() + 15 * 24 * 3600 * 1000), // In 15 days
      });

      const exam = await Exam.create({
        name: `Thi TN ${lc.name} K26`,
        exam_type: 'graduation',
        status: 'upcoming',
        start_time: new Date(TODAY.getTime() + 5 * 24 * 3600 * 1000), // In 5 days
        location: 'Sân tập Trung tâm',
        license_category_id: lc._id,
      });

      await ExamSchedule.create({
        exam_id: exam._id,
        start_time: new Date(TODAY.getTime() + 5 * 24 * 3600 * 1000 + 8 * 3600 * 1000),
        end_time: new Date(TODAY.getTime() + 5 * 24 * 3600 * 1000 + 17 * 3600 * 1000),
      });
    }

    // --- PHASE 6: INTEGRATION ---
    logger.info('📱 SEEDING INTEGRATION DATA...');
    await Announcement.create({
      title: 'Thông báo Sát hạch Tháng 4/2026',
      content: 'Lịch thi sát hạch các hạng B1, B2 sẽ diễn ra từ ngày 20/04/2026. Học viên lưu ý kiểm tra hồ sơ.',
      target_group: 'ALL',
      channels: ['APP'],
      status: 'SENT',
    });

    await Notification.create({
      title: 'Lịch học sắp tới',
      body: 'Bạn có buổi học thực hành vào 08:00 sáng mai.',
      receive_id: admin._id,
      receive_type: 'user',
      is_read: false,
    });

    logger.info('✨ ULTIMATE SEED V5.0 SUCCESSFUL! ✨');
    process.exit(0);
  } catch (error) {
    logger.error('❌ SEED ERROR:', error);
    process.exit(1);
  }
};

runUltimateSeed();

import { Router } from 'express';
import authRoutes from './auth.routes';
import studentRoutes from './student.routes';
