import type {} from './interface/types/express.d';
import dotenv from 'dotenv';
dotenv.config(); // Must be BEFORE importing app (imports are hoisted)
import type { Server } from 'http';
import mongoose from 'mongoose';
import connectDB from '@/infrastructure/database/mongodb';
import logger from '@/infrastructure/logging/logger';
import app from './app';

import { seedStaticData } from '@/infrastructure/database/seeders/data.seeder';

const PORT = Number(process.env.PORT || 5002);
let server: Server | null = null;

const shutdown = async (signal: NodeJS.Signals) => {
  logger.warn(`${signal} received. Shutting down gracefully...`);

  try {
    if (server) {
      await new Promise<void>((resolve, reject) => {
        server!.close((error) => {
          if (error) return reject(error);
          resolve();
        });
      });
    }

    await mongoose.connection.close();
    logger.info('HTTP server and MongoDB connection closed');
    process.exit(0);
  } catch (error) {
    logger.error('Graceful shutdown failed', error);
    process.exit(1);
  }
};

const start = async () => {
  try {
    await connectDB();
    await seedStaticData();

    server = app.listen(PORT, '0.0.0.0', () => {
      logger.info(`Server running on port ${PORT}`);
    });
  } catch (error) {
    logger.error('Failed to start server', error);
    process.exit(1);
  }
};

process.on('SIGINT', () => {
  void shutdown('SIGINT');
});

process.on('SIGTERM', () => {
  void shutdown('SIGTERM');
});

start();

import express from 'express';
import cors from 'cors';
import cookieParser from 'cookie-parser';
import swaggerUi from 'swagger-ui-express';
import helmet from 'helmet';
import { xssMiddleware } from '@/interface/middlewares/xss.middleware';
import { globalRateLimit } from '@/interface/middlewares/rate-limit.middleware';
import { jsonResponseMiddleware } from '@/interface/middlewares/response.middleware';
import { globalErrorHandler } from '@/interface/middlewares/error.middleware';
import router from '@/interface/routes/index';
import * as swaggerDocument from './interface/docs/swagger.json';

const app = express();

// 1. CORS MUST be at the top to handle Preflight (OPTIONS)
const ALLOWED_ORIGINS = [
  process.env.FRONTEND_URL,
  process.env.FRONTEND_URL_2,
  /\.vercel\.app$/,
  'http://localhost:3001',
  'http://localhost:3000',
  'http://localhost:3002',
  'http://103.253.21.139:3002',
  'http://103.253.21.139:3000',
].filter(Boolean);

app.use(
  cors({
    origin: ALLOWED_ORIGINS as (string | RegExp)[],
    credentials: true,
  }),
);

// 2. Decorate Response object early
app.use(jsonResponseMiddleware);

// 3. Security Headers with Cross-Origin support
app.use(
  helmet({
    crossOriginResourcePolicy: { policy: 'cross-origin' },
  }),
);

// 4. Other Global Middlewares
app.use(xssMiddleware);
app.use(globalRateLimit);
app.use(express.json());
app.use(cookieParser());

// Swagger Documentation
app.use('/api-docs', swaggerUi.serve, swaggerUi.setup(swaggerDocument));

// Root Health Check — for infrastructure monitoring (Docker, K8s, Render)
app.get('/health', (_req, res) => {
  res.status(200).json({
    status: 'ok',
    service: 'dtlx-api',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

// Main Router
app.use('/api/v1', router);

// Error Handler
app.use(globalErrorHandler);

export default app;

/**
 * Role definitions for the system
 */
export enum Role {
  SUPERADMIN = 'superadmin',
  TEACHER = 'teacher',
