import mongoose, { Schema, Document, Types } from 'mongoose';

// Role names as defined in Master AHV system
export enum UserRoleName {
  Admin = 'admin',
  SuperAdmin = 'superadmin',
  Teacher = 'teacher',
  Staff = 'staff',
  Sale = 'sale',
  Student = 'student',
  Lead = 'lead',
  User = 'user',
}

export interface IRole extends Document {
  _id: Types.ObjectId;
  role_name: string;
  created_at: Date;
  updated_at: Date;
}

const RoleSchema = new Schema<IRole>(
  {
    role_name: {
      type: String,
      trim: true,
      unique: true,
      required: [true, 'Tên vai trò là bắt buộc'],
    },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'roles',
  },
);

// Removed duplicate index since unique: true already creates one

export const RoleModel = mongoose.models.Roles || mongoose.model<IRole>('Roles', RoleSchema, 'roles');

