import logger from '@/infrastructure/logging/logger';

const CITIES = [
  'TP. Hà Nội (Mở rộng)',
  'TP. Hải Phòng',
  'TP. Đà Nẵng',
  'TP. Hồ Chí Minh',
  'TP. Cần Thơ',
  'TP. Biên Hòa (Mới)',
  'Hà Giang - Tuyên Quang (Sáp nhập)',
  'Lào Cai - Yên Bái (Sáp nhập)',
  'Thái Nguyên - Bắc Kạn (Sáp nhập)',
  'Phú Thọ - Vĩnh Phúc (Sáp nhập)',
  'Bắc Giang - Bắc Ninh (Sáp nhập)',
  'Quảng Ninh',
  'Hòa Bình - Sơn La (Sáp nhập)',
  'Thanh Hóa',
  'Nghệ An',
