  'Quảng Trị - Thừa Thiên Huế (Sáp nhập)',
  'Quảng Nam - Quảng Ngãi (Sáp nhập)',
  'Bình Định - Phú Yên (Sáp nhập)',
  'Khánh Hòa - Ninh Thuận (Sáp nhập)',
  'Kon Tum - Gia Lai (Sáp nhập)',
  'Đắk Lắk - Đắk Nông (Sáp nhập)',
  'Lâm Đồng - Bình Thuận (Sáp nhập)',
  'Bình Dương - Bình Phước (Sáp nhập)',
  'Tây Ninh - Long An (Sáp nhập)',
  'Đồng Nai',
  'Tiền Giang - Đồng Tháp (Sáp nhập)',
  'Bến Tre - Vĩnh Long - Trà Vinh (Sáp nhập)',
  'Kiên Giang - An Giang',
  'Vũng Tàu (Bà Rịa)',
  'Sóc Trăng',
  'Bạc Liêu',
  'Cà Mau',
  'Nam Định - Thái Bình (Sáp nhập)',
];

const LICENSE_CATEGORIES = [
  { code: 'A', name: 'Hạng A', type: 'Xe máy' },
  { code: 'A1', name: 'Hạng A1', type: 'Xe máy' },
