  { code: 'B1', name: 'Hạng B1', type: 'Ô tô' },
  { code: 'BE', name: 'Hạng BE', type: 'Ô tô' },
  { code: 'C', name: 'Hạng C', type: 'Ô tô' },
  { code: 'C1', name: 'Hạng C1', type: 'Ô tô' },
  { code: 'C1E', name: 'Hạng C1E', type: 'Ô tô' },
  { code: 'CE', name: 'Hạng CE', type: 'Ô tô' },
  { code: 'D', name: 'Hạng D', type: 'Ô tô' },
  { code: 'D1', name: 'Hạng D1', type: 'Ô tô' },
  { code: 'D1E', name: 'Hạng D1E', type: 'Ô tô' },
  { code: 'D2', name: 'Hạng D2', type: 'Ô tô' },
  { code: 'D2E', name: 'Hạng D2E', type: 'Ô tô' },
  { code: 'DE', name: 'Hạng DE', type: 'Ô tô' },
];

export const seedStaticData = async () => {
  try {
    logger.info('🚀 Starting data seeding...');

    // Seed Cities
    let cityCount = 0;
    for (const cityName of CITIES) {
      const code = cityName.toLowerCase()
        .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
        .replace(/[^a-z0-9]/g, '-')
        .replace(/-+/g, '-')
        .replace(/^-|-$/g, '');

      const exists = await CityModel.findOne({ code });
      if (!exists) {
        await CityModel.create({ name: cityName, code });
        cityCount++;
      }
    }
    if (cityCount > 0) logger.info(`✅ Seeded ${cityCount} new cities.`);

    // Seed License Categories
    let categoryCount = 0;
    for (const cat of LICENSE_CATEGORIES) {
      const exists = await LicenseCategoryModel.findOne({ code: cat.code });
      if (!exists) {
        await LicenseCategoryModel.create(cat);
        categoryCount++;
      }
    }
    if (categoryCount > 0) logger.info(`✅ Seeded ${categoryCount} new license categories.`);

    logger.info('🏁 Data seeding completed.');
  } catch (error) {
    logger.error('❌ Error during data seeding:', error);
  }
};

