import bcrypt from 'bcrypt';
import { UserModel, UserGender, UserStatus } from '../models/user.model';
import { RoleModel, UserRoleName } from '../models/role.model';
import { UserRoleModel } from '../models/user_role.model';
import logger from '@/infrastructure/logging/logger';

export const seedEssentialUsers = async () => {
  try {
    logger.info('🚀 Checking essential roles and users...');

    // 1. Ensure Roles exist
    const rolesToSeed = Object.values(UserRoleName);
    for (const roleName of rolesToSeed) {
      const existingRole = await RoleModel.findOne({ role_name: roleName });
      if (!existingRole) {
        await RoleModel.create({ role_name: roleName });
        logger.info(`✅ Created role: ${roleName}`);
      }
    }

    const adminRole = await RoleModel.findOne({ role_name: UserRoleName.SuperAdmin });
    const teacherRole = await RoleModel.findOne({ role_name: UserRoleName.Teacher });

    if (!adminRole || !teacherRole) {
      throw new Error('Required roles (Admin/Teacher) could not be found or created.');
    }

    const commonPasswordHash = await bcrypt.hash('Admin@123456', 10);
    const teacherPasswordHash = await bcrypt.hash('Teacher@123456', 10);

    // 2. Seed Admin User
    const adminUsername = 'admin@qlhv.vn';
    let adminUser = await UserModel.findOne({ username: adminUsername });
    if (!adminUser) {
      adminUser = await UserModel.create({
        username: adminUsername,
        first_name: 'Quản trị viên',
        last_name: 'Hệ thống',
        email: adminUsername,
        phone: '0988776655',
        address: 'Hà Nội',
        identity_card: '001000000001',
        gender: UserGender.Male,
        status: UserStatus.Active,
        password: commonPasswordHash,
      });
      logger.info(`✅ Seeded Admin user: ${adminUsername}`);
    }

    // Link Admin to Role
    const existingAdminRoleLink = await UserRoleModel.findOne({
      user_id: adminUser._id,
      role_id: adminRole._id,
    });
    if (!existingAdminRoleLink) {
      await UserRoleModel.create({
        user_id: adminUser._id,
        role_id: adminRole._id,
      });
      logger.info(`🔗 Linked Admin user to Admin role`);
    }

    // 3. Seed Teacher User
    const teacherUsername = 'teacher@qlhv.vn';
    let teacherUser = await UserModel.findOne({ username: teacherUsername });
    if (!teacherUser) {
      teacherUser = await UserModel.create({
        username: teacherUsername,
        first_name: 'Giảng viên',
        last_name: 'Mẫu',
        email: teacherUsername,
        phone: '0912345678',
