import { Request, Response, NextFunction } from 'express';
import { Role, SUPERADMIN_ONLY_MODULES } from '@/domain/constants/rbac';

export const rbacMiddleware = (allowedRoles: string[]) => {
  return (req: Request, res: Response, next: NextFunction) => {
    // 1. Lấy user từ request (đã được Auth middleware populate)
    const user = (req as any).user;

    if (!user) {
      return res.status(401).json({
        success: false,
        message: 'Không hợp lệ: Không tìm thấy thông tin người dùng',
      });
    }

    // 2. Kiểm tra vai trò
    const hasRole = allowedRoles.includes(user.role);

    if (!hasRole) {
      return res.status(403).json({
        success: false,
        message: `Truy cập bị từ chối: Yêu cầu quyền truy cập của [${allowedRoles.join(', ')}]`,
      });
    }

    next();
  };
};

/**
 * Middleware to restrict access to superadmin-only modules
 */
export const moduleAccessGuard = (moduleName: string) => {
  return (req: Request, res: Response, next: NextFunction) => {
    const user = (req as any).user;

    if (!user) {
      return res.status(401).json({ success: false, message: 'Không hợp lệ: Chưa xác thực' });
    }

    // Superadmin bypass
    if (user.role === Role.SUPERADMIN) {
      return next();
    }

    // Check if module is superadmin only
    if (SUPERADMIN_ONLY_MODULES.includes(moduleName as any)) {
      return res.status(403).json({
        success: false,
        message: 'Truy cập bị từ chối: Chức năng này chỉ dành cho Quản trị viên hệ thống',
      });
    }

    next();
  };
};

